// 获取文档所有段落的文本和样式信息
var doc = Application.ActiveDocument;
var result = [];
var paraCount = doc.Paragraphs.Count;

for (var i = 1; i <= paraCount; i++) {
    var para = doc.Paragraphs.Item(i);
    var text = para.Range.Text.replace(/\r\n/g, '').replace(/\n/g, '');
    if (text.trim()) {
        result.push({
            index: i,
            text: text,
            style: para.Style ? para.Style.NameLocal : '无样式'
        });
    }
}

return result.slice(0, 50);
